/**
 * StrategyRentalCard -- "Rent this strategy" CTA card.
 * Used on StrategyCataloguePage and StrategyDetailPage.
 *
 * Props:
 *   strategy  - Strategy object with stats
 *   compact   - Slim inline badge mode (for catalogue rows)
 *   onRent    - Optional callback
 */
import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { tokens } from '../styles/tokens';
import { getStrategyRentalPrice, isTopPerformingRental, RENTAL_PRICING } from '../utils/monetization';
import { getUserTier, TIER_LEVELS } from '../hooks/useTierGate';

const T = {
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, amber: tokens.color.amber, purple: tokens.color.purple,
  blue: tokens.color.blue, border: tokens.color.border, surface2: tokens.color.surfaceHover,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

export default function StrategyRentalCard({ strategy, compact = false, onRent }) {
  const nav = useNavigate();
  const [mode, setMode] = useState('signal');
  const isTop = isTopPerformingRental(strategy);
  const signalPrice = getStrategyRentalPrice(strategy, 'signal');
  const autoPrice = getStrategyRentalPrice(strategy, 'auto');
  const currentPrice = mode === 'signal' ? signalPrice : autoPrice;

  const handleRent = () => {
    if (onRent) {
      onRent(strategy, mode, currentPrice);
    } else {
      nav(`/marketplace?rent=${encodeURIComponent(strategy?.key || strategy?.name)}&mode=${mode}`);
    }
  };

  // Compact badge mode for catalogue table rows
  if (compact) {
    return (
      <div style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}>
        {isTop && (
          <span style={{
            fontSize: 9, fontWeight: 700, fontFamily: T.mono,
            color: T.amber, background: `${T.amber}15`, border: `1px solid ${T.amber}25`,
            borderRadius: 4, padding: '1px 5px', textTransform: 'uppercase',
            letterSpacing: '0.03em',
          }}>
            Top Rental
          </span>
        )}
        <button
          onClick={(e) => { e.stopPropagation(); handleRent(); }}
          style={{
            fontSize: 10, fontWeight: 700, fontFamily: T.mono,
            color: T.green, background: `${T.green}10`, border: `1px solid ${T.green}22`,
            borderRadius: 4, padding: '2px 8px', cursor: 'pointer',
            whiteSpace: 'nowrap',
          }}
          onMouseEnter={(e) => { e.currentTarget.style.background = `${T.green}20`; }}
          onMouseLeave={(e) => { e.currentTarget.style.background = `${T.green}10`; }}
        >
          Rent ${signalPrice.toFixed(2)}/mo
        </button>
      </div>
    );
  }

  // Full card mode for strategy detail page
  return (
    <div style={{
      background: `linear-gradient(135deg, ${T.green}06, ${T.purple}06)`,
      border: `1px solid ${T.green}20`,
      borderRadius: 14, padding: '20px 24px', marginBottom: 16,
      fontFamily: T.sans,
    }}>
      {/* Header with badge */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
          <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke={T.green} strokeWidth="2">
            <circle cx="12" cy="12" r="10" />
            <path d="M16 8l-8 8M8 8h8v8" />
          </svg>
          <span style={{ fontSize: 15, fontWeight: 700, color: T.text }}>
            Rent This Strategy
          </span>
        </div>
        {isTop && (
          <span style={{
            fontSize: 10, fontWeight: 700, fontFamily: T.mono,
            color: '#000', background: T.amber,
            borderRadius: 6, padding: '3px 10px', textTransform: 'uppercase',
            letterSpacing: '0.04em',
          }}>
            Top Performing Rental
          </span>
        )}
      </div>

      {/* Mode toggle */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        {['signal', 'auto'].map(m => (
          <button
            key={m}
            onClick={() => setMode(m)}
            style={{
              flex: 1, padding: '10px 14px', borderRadius: 8,
              background: mode === m ? `${T.green}15` : 'transparent',
              border: `1px solid ${mode === m ? T.green + '44' : T.border}`,
              cursor: 'pointer', textAlign: 'left',
            }}
          >
            <div style={{ fontSize: 13, fontWeight: 700, color: mode === m ? T.green : T.text, fontFamily: T.mono }}>
              {m === 'signal' ? 'Signal Only' : 'Auto-Execute'}
            </div>
            <div style={{ fontSize: 11, color: T.textSec, marginTop: 2 }}>
              {m === 'signal'
                ? 'Get alerts when this strategy fires'
                : 'Automatically place trades'
              }
            </div>
            <div style={{ fontSize: 16, fontWeight: 800, color: mode === m ? T.green : T.textSec, fontFamily: T.mono, marginTop: 4 }}>
              ${m === 'signal' ? signalPrice.toFixed(2) : autoPrice.toFixed(2)}/mo
            </div>
          </button>
        ))}
      </div>

      {/* Revenue share callout */}
      <div style={{
        fontSize: 11, color: T.textSec, marginBottom: 14, padding: '8px 12px',
        background: T.surface2, borderRadius: 8, border: `1px solid ${T.border}`,
        lineHeight: 1.5,
      }}>
        Strategy creators earn <strong style={{ color: T.green }}>70%</strong> of rental revenue.
        Build and publish your own strategies in the <span style={{ color: T.blue, cursor: 'pointer' }}
          onClick={() => nav('/strategy-lab')}>Strategy Lab</span>.
      </div>

      {/* Rent CTA */}
      <button
        onClick={handleRent}
        style={{
          width: '100%', padding: '12px 20px', borderRadius: 10,
          fontSize: 14, fontWeight: 700, fontFamily: T.mono,
          color: '#fff', border: 'none', cursor: 'pointer',
          background: `linear-gradient(135deg, ${T.green}, ${T.blue})`,
          boxShadow: `0 4px 16px ${T.green}33`,
        }}
        onMouseEnter={(e) => { e.currentTarget.style.opacity = '0.9'; }}
        onMouseLeave={(e) => { e.currentTarget.style.opacity = '1'; }}
      >
        Rent for ${currentPrice.toFixed(2)}/mo
      </button>
    </div>
  );
}
